#[cfg(target_arch = "loongarch64")]
fn arm_watchdog_tick() {
    use core::arch::asm;

    let freq = polyhal::timer::get_freq();
    let ticks = (freq / 100).max(4) & !3;
    let value = ((ticks >> 2) << 2) | 1;
    unsafe {
        asm!("csrwr {}, 0x41", in(reg) value, options(nostack));
    }
}

#[cfg(not(target_arch = "loongarch64"))]
fn arm_watchdog_tick() {
    set_next_timer(current_time() + Duration::from_millis(10));
}

