        paddr.clear_len(PAGE_SIZE);
        let mut frames = PAGE_TABLE_FRAMES.lock();
        if !frames.contains(&paddr.raw()) {
            frames.push(paddr.raw());
        }
        paddr
    }

    #[inline]
    fn dealloc(&self, paddr: PhysAddr) {
        let mut frames = PAGE_TABLE_FRAMES.lock();
        if let Some(index) = frames.iter().position(|frame| *frame == paddr.raw()) {
            frames.swap_remove(index);
        } else {
            return;
        }
        drop(frames);

        unsafe {
            paddr.clear_len(PAGE_SIZE);
            frame_unalloc(paddr);
        }
    }

    #[inline]
    fn contains(&self, paddr: PhysAddr) -> bool {
        PAGE_TABLE_FRAMES.lock().contains(&paddr.raw())
    }
}

