general-plic = { workspace = true }
ns16550a = { workspace = true }

OUTPUT_ARCH(%ARCH%)
ENTRY(__entry)

BASE_ADDRESS = %KERNEL_BASE%;
ENTRY_ADDRESS = %ENTRY_ADDR%;
LOAD_OFFSET = BASE_ADDRESS - ENTRY_ADDRESS;

SECTIONS
{
    . = BASE_ADDRESS;
    _skernel = .;
    __entry = ENTRY_ADDRESS;

    .text ALIGN(4K): AT(ADDR(.text) - LOAD_OFFSET) {
        *(.multiboot .multiboot.*)
        stext = .;
        KEEP(*(.text.entry))
        *(.text .text.*)
        etext = .;
    }

    .rodata ALIGN(4K): AT(ADDR(.rodata) - LOAD_OFFSET) {
        srodata = .;
        *(.rodata .rodata.*)
        erodata = .;
    }

    .got : AT(ADDR(.got) - LOAD_OFFSET) {
        *(.got .got.*)
    }

    .data ALIGN(4K): AT(ADDR(.data) - LOAD_OFFSET) {
        _sdata = .;
        . = ALIGN(4K);
        *(.data.boot_page_table)

        *(.data .data.*)
        *(.sdata .sdata.*)
        _edata = .;
    }

    .bss ALIGN(4K): AT(ADDR(.bss) - LOAD_OFFSET) {
        _load_end = .;
        *(.bss.bstack .bss.bstack.*)
        _sbss = .;
        *(.bss .bss.*)
        *(.sbss .sbss.*)
        _ebss = .;
    }

    PROVIDE(_end = .);
    /DISCARD/ : {
        *(.comment) *(.gnu*) *(.note*) *(.eh_frame*)
    }
}

#!/usr/bin/env -S deno --ext=ts --allow-run --allow-read --allow-env

import { Command } from "https://deno.land/x/cliffy@v1.0.0-rc.4/command/mod.ts";
import { cliCommand as buildCommand } from "./scripts/cli-build.ts";
import { cliCommand as qemuCommand } from "./scripts/cli-qemu.ts";
import { logLevelEnum } from "./scripts/cli-types.ts";
import { parse } from "jsr:@std/yaml";
import { initPlatform } from "./scripts/platform.ts";

const command = new Command()
    .name("byteos")
    .version("0.1.0")
    .description("Building tools for the byteos.")
    .globalType("log-level", logLevelEnum)
    .globalOption("-l, --log-level <level:log-level>", "Set Log Level", {
        default: "info",
    })
    .globalOption("-p, --platform <string>", "Set the platform", {
        required: true,
    })
    .globalAction(({ platform }) => initPlatform(platform))
    // Sub Command build
    .command("build", buildCommand)
    .command("qemu", qemuCommand);

// parse yaml file
const data = parse(
    new TextDecoder("utf-8").decode(await Deno.readFile("byteos.yaml")),
);
console.log(data);

try {
    // Parse the command.
    await command.parse(Deno.args);
} catch (e) {
    console.error("Error", e);
}

